import java.io.*; // for InputStream, OutputStream, FileInputStream etc., use direct path 'file' and not a full package name like fileutil or com.sun.* (unless you want to load system files) such as Paths from sun.nio library which is used only when working with external libraries
import java.security.*; // for MessageDigest instances, they are included in standard Java SE but can be loaded separately if needed  e.g., import org.apache.commons.codec.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for ArrayList instances, use direct path 'arrayList'. It is included in Java SE but can be loaded separately if needed e.g., import org.apache.commons.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for HashMap instances, use direct path 'Hashmap'. It is included in Java SE but can be loaded separately if needed e.g., import org.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for HashSet instances, use direct path 'Hashset'. It is included in Java SE but can be loaded separately if needed e.g., import org.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for LinkedList instances, use direct path 'Linkedlist'. It is included in Java SE but can be loaded separately if needed e.g., import org.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for Queue instances, use direct path 'Queue', it includes classes from both LinkedList (implements Deque interface) as well  e.g., import org.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance
import java_util.*; // for Stack instances, use direct path 'Stack', it includes classes from both ArrayList (implements List interface) as well  e.g., import org.*; or similar like this   . Importing all of them would consume too much resources and could slow down the application's performance